module.exports = /*#__PURE__*/JSON.parse('[{"id":"improved-clinch","name":"Improved Clinch Knot","useCase":"Your everyday knot for tying line to a hook, lure, or swivel.","steps":["Thread the tag end of your line through the eye of the hook and pull about 15 cm through.","Twist the tag end around the standing line five to seven times, keeping the wraps neat.","Bring the tag end back and pass it through the small loop just above the hook eye.","Now feed the tag end through the larger loop you just created.","Moisten the knot with saliva, then pull the standing line slowly so the coils cinch down against the eye.","Trim the tag end, leaving roughly 2 mm."],"youtubeId":"HCjaUcdRDR0","videoTitle":"Salt Strong — How To Tie The Clinch Knot Video Tutorial","animatedYoutubeId":"0JpZlOf_5JI","animatedVideoTitle":"Animated Knots by Grog — Improved Clinch Knot"},{"id":"palomar","name":"Palomar Knot","useCase":"The strongest knot for attaching terminal tackle when you\'re fishing braid.","steps":["Double about 15 cm of line and pass the loop through the hook eye.","Tie a loose overhand knot with the doubled line — don\'t tighten it yet.","Open the loop at the end and pass the entire hook through it.","Pull both the tag end and standing line to draw the knot down to the hook eye.","Wet the knot and pull firmly until it seats tight against the eye.","Trim the tag end close."],"youtubeId":"TFk_Ktw2f1w","videoTitle":"Salt Strong — Palomar Knot: Quick Tutorial","animatedYoutubeId":"GZpPJB-EwUc","animatedVideoTitle":"Animated Knots by Grog — Palomar Knot"},{"id":"uni","name":"Uni Knot","useCase":"Versatile knot — works for line-to-hook and, doubled up, for line-to-line joins.","steps":["Pass the tag end through the hook eye and double back alongside the standing line.","Form a loop by laying the tag end back over the doubled line.","Wrap the tag end through the loop and around the doubled line six times.","Moisten the wraps, then pull the tag end to snug the coils together.","Pull the standing line to slide the tightened knot down to the hook eye.","Trim the tag end."],"youtubeId":"3lchV7Ikh1U","videoTitle":"NetKnots — How to tie the Uni Knot","animatedYoutubeId":"Mr1ngSO5jvQ","animatedVideoTitle":"Animated Knots by Grog — Uni Knot"},{"id":"blood","name":"Blood Knot","useCase":"For joining two lines of similar diameter — typically a leader to your mainline.","steps":["Overlap the ends of the two lines you want to join by about 15 cm.","Wrap one tag end around the other line five to seven times and tuck it back between the two lines.","Hold that tuck in place, then repeat with the other tag end — same wrap count, tucking through the same gap from the opposite side.","Wet the knot generously.","Pull the two standing lines apart slowly so the wraps cinch together into a neat barrel.","Trim both tag ends close to the knot."],"youtubeId":"A_XJPYTilYI","videoTitle":"NetKnots — How to tie the Blood Knot","animatedYoutubeId":"OCkv0LRcRm0","animatedVideoTitle":"Animated Knots by Grog — Blood Knot"},{"id":"non-slip-loop","name":"Non-Slip Loop Knot","useCase":"Creates a fixed loop at the lure so it can swim and move naturally on the retrieve.","steps":["Tie a loose overhand knot in the line roughly 20 cm from the tag end — don\'t tighten.","Pass the tag end through the lure eye, then back through the overhand loop.","Wrap the tag end around the standing line five times (use fewer wraps on heavier line).","Feed the tag end back through the overhand loop, exiting the same side it entered.","Moisten the knot and pull the tag end to tighten the wraps.","Pull the standing line to seat the knot, leaving the loop intact. Trim the tag."],"youtubeId":"C0u5HQBiv_I","videoTitle":"Salt Strong — How To Tie A Non-Slip Loop Knot","animatedYoutubeId":"hRcyz3Z1F6c","animatedVideoTitle":"Animated Knots by Grog — Non-Slip Loop Knot"},{"id":"double-uni","name":"Double Uni Knot","useCase":"Reliable line-to-line join — works for braid-to-mono and leaders of similar or slightly different diameter.","steps":["Overlap the ends of the two lines by about 20 cm so they run alongside each other.","Take the tag end of the first line and form a loop back over both lines.","Wrap that tag end through the loop and around both lines five to six times (use six to eight wraps for braid).","Moisten the wraps and pull the tag end to snug the first uni knot down — don\'t seat it fully yet.","Repeat the same loop and wraps with the second line\'s tag end, going the opposite direction.","Wet the whole join and pull the two standing lines apart steadily so the two uni knots slide together and lock against each other.","Trim both tag ends close."],"youtubeId":"JJDjr-_Pw_U","videoTitle":"NetKnots — How to tie the Double Uni Knot","animatedYoutubeId":"wqWfsAKHrUI","animatedVideoTitle":"Animated Knots by Grog — Double Uni Knot"},{"id":"fg-knot","name":"FG Knot","useCase":"Low-profile braid-to-leader knot — slim enough to slide through rod guides on the cast.","steps":["Hold your braid taut between your teeth and your reel hand, then lay the leader across it forming an X.","Wrap the braid around the leader by rolling the leader — alternate which side the braid passes over so the wraps stack neatly. Aim for 18-24 wraps.","Pinch the wraps with one hand, then lock them in place with two half-hitches around the leader using the braid\'s tag end.","Trim the leader\'s tag end close, leaving 1-2 mm.","Tie five to seven more half-hitches with the braid tag, alternating the direction of each hitch around the standing braid.","Finish with a four-turn locking hitch, moisten everything, and pull tight.","Trim the braid tag close. The finished knot should be slim and feel smooth when run between your fingers."],"youtubeId":"WrazkHkEnQU","videoTitle":"Salt Strong — How To Tie The FG Knot","animatedYoutubeId":"SBdXZ7nQO1Q","animatedVideoTitle":"Animated Knots — FG Knot Step-by-Step"},{"id":"albright","name":"Albright Knot","useCase":"Joining two lines of very different diameters — heavy mono leader to lighter braid or mono mainline.","steps":["Form a loop in the heavier line and pinch it between your fingers.","Pass the lighter line\'s tag end through the loop, leaving about 25 cm to work with.","Wrap the tag end of the lighter line back over both strands of the heavy line loop ten to twelve times, working towards the closed end of the loop.","Pass the tag end back through the loop, exiting on the same side it entered.","Wet the knot, then pull on the standing parts of both lines while sliding the wraps tight against the closed end of the loop.","Pull firmly on both standing lines to fully seat the knot.","Trim both tag ends close."],"youtubeId":"5tH7r6Vno-w","videoTitle":"NetKnots — How to tie the Albright Knot","animatedYoutubeId":"rHnVpYUvQqM","animatedVideoTitle":"Animated Knots by Grog — Albright Knot"},{"id":"surgeons","name":"Double Surgeon\'s Knot","useCase":"Fast, strong line-to-line knot — the easiest way to add a fluorocarbon leader on the rocks when fingers are cold.","steps":["Lay the two lines you want to join alongside each other, overlapping by about 20 cm.","Treating both lines as one, form a simple loop.","Pass both the leader and the tag end of the mainline through the loop together — once.","Pass them through the loop a second time (this is what makes it a double surgeon\'s).","Moisten the knot.","Hold both standing lines in one hand and both tag ends in the other, then pull all four strands apart firmly and evenly to seat the knot.","Trim both tag ends close."],"youtubeId":"AcUmsl5Sk_o","videoTitle":"NetKnots — How to tie the Double Surgeon\'s Knot","animatedYoutubeId":"fMxwnhlnBhk","animatedVideoTitle":"Animated Knots by Grog — Surgeon\'s Knot"},{"id":"snell","name":"Snell Knot","useCase":"Attaches the line directly to the shank of a hook for straight-pull power — ideal for circle hooks when bait fishing.","steps":["Pass the tag end through the hook eye from the point side, then back through from the opposite side, leaving a long loop running down the shank.","Hold the hook and the doubled line together with your non-dominant hand.","Take the loop and start wrapping it around both the hook shank and the standing line, working from the eye towards the bend.","Make seven to ten neat wraps, keeping each one tight against the last.","Hold the wraps in place and pull the standing line slowly — the loop will collapse and the wraps will tighten down onto the shank.","Wet the knot as it cinches and pull firmly to seat. The line should now exit the eye in line with the hook point.","Trim the tag end close to the wraps."],"youtubeId":"_xGAg-WEpbY","videoTitle":"NetKnots — How to tie the Snell Knot","animatedYoutubeId":"ZRz0n2_-jpk","animatedVideoTitle":"Animated Knots by Grog — Snell Knot"},{"id":"dropper-loop","name":"Dropper Loop","useCase":"Creates a standing loop in the middle of the line for attaching a second hook — the foundation of paternoster and sabiki rigs.","steps":["Find the spot in your line where you want the dropper and form a loop, leaving plenty of slack.","Take the bottom of the loop and pass it up through the centre of the loop, twisting the line as you go to make a small opening at the centre.","Continue passing the loop through the centre opening five or six times — the wraps will start to stack on either side.","Pinch the centre opening to keep it from closing, then reach through and pull the original loop fully through.","Moisten the knot generously.","Pull both standing ends of the line apart steadily so the wraps cinch down and the loop stands out at 90° from the line.","Attach a hook or short snood to the loop using a loop-to-loop connection."],"youtubeId":"VlBJTIINIIs","videoTitle":"NetKnots — How to tie the Dropper Loop","animatedYoutubeId":"tZpKjV4EZcI","animatedVideoTitle":"Animated Knots by Grog — Dropper Loop"}]');

